import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  MapPin,
  Heart,
  Trash2,
  Tag,
  ChevronRight,
  ShoppingBag
} from 'lucide-react';
import { useCart } from '../hooks/usecart'; // Your custom hook

const CartPage = () => {
  const navigate = useNavigate();

  // Using your exact custom hook structure
  const { items, removeItem, changeQuantity, getCartTotal } = useCart();

  // Local state for UI interactions
  const [pincode, setPincode] = useState('');
  const [couponCode, setCouponCode] = useState('SUMMER26');
  const [isCouponApplied, setIsCouponApplied] = useState(true);

  // ==========================================
  // CRASH-PROOF PRICE HELPERS
  // ==========================================
  const getSafePrice = (item) => {
    return item.price || item.finalPrice || item.variants?.[0]?.price || 0;
  };

  const getSafeMrp = (item) => {
    // Creates a realistic MRP if your database doesn't supply one yet
    return item.mrp || item.originalPrice || Math.round(getSafePrice(item) * 2.13);
  };

  // ==========================================
  // CART CALCULATIONS
  // ==========================================
  const totalItems = items.reduce((acc, item) => acc + (item.quantity || 1), 0);

  const totalMrp = items.reduce((acc, item) => {
    return acc + (getSafeMrp(item) * (item.quantity || 1));
  }, 0);

  const totalDiscountedPrice = items.reduce((acc, item) => {
    return acc + (getSafePrice(item) * (item.quantity || 1));
  }, 0);

  const baseDiscount = totalMrp - totalDiscountedPrice;
  const couponDiscount = isCouponApplied && items.length > 0 ? 10750 : 0;

  // We use your getCartTotal() as the base, then subtract the UI coupon
  const finalPayable = (getCartTotal ? getCartTotal() : totalDiscountedPrice) - couponDiscount;
  const totalSavings = baseDiscount + couponDiscount;

  // ==========================================
  // EMPTY STATE RENDER
  // ==========================================
  if (items.length === 0) {
    return (
      <div className="bg-gray-50 min-h-[70vh] flex flex-col items-center justify-center px-4 py-16">
        <div className="bg-white p-12 rounded-xl shadow-sm border border-gray-100 text-center max-w-lg w-full">
          <div className="w-24 h-24 bg-orange-50 rounded-full flex items-center justify-center mx-auto mb-6">
            <ShoppingBag size={40} className="text-[#f97316]" />
          </div>
          <h2 className="text-2xl font-bold text-gray-900 mb-3 tracking-tight">Your cart is empty</h2>
          <p className="text-gray-500 mb-8">Looks like you haven't added any premium furniture to your cart yet.</p>
          <Link
            to="/"
            className="inline-block bg-[#f97316] text-white px-8 py-3.5 rounded-lg font-bold hover:bg-orange-600 transition-all duration-300 w-full tracking-wide shadow-md hover:shadow-orange-500/20 active:scale-[0.98]"
          >
            START SHOPPING
          </Link>
        </div>
      </div>
    );
  }

  // ==========================================
  // MAIN CART RENDER
  // ==========================================
  return (
    <div className="bg-[#f4f5f7] min-h-screen py-8 font-sans">
      <div className="container mx-auto px-4 max-w-6xl">

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-start">

          {/* ----------------------------------------------------- */}
          {/* LEFT COLUMN: CART ITEMS */}
          {/* ----------------------------------------------------- */}
          <div className="lg:col-span-8 flex flex-col gap-4">

            {/* Cart Header & Pincode */}
            <div className="bg-white shadow-sm rounded-sm">
              <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center p-4 sm:p-5 border-b border-gray-100 gap-4 sm:gap-0">
                <h1 className="text-lg font-bold text-gray-900">
                  My Cart ({totalItems})
                </h1>

                <div className="flex items-center gap-3 w-full sm:w-auto">
                  <div className="flex items-center text-gray-600 shrink-0">
                    <MapPin size={18} className="mr-1" />
                    <span className="text-sm font-medium">Deliver To</span>
                  </div>
                  <div className="flex items-center border border-gray-300 rounded-sm overflow-hidden w-full sm:w-auto focus-within:border-orange-400 focus-within:ring-1 focus-within:ring-orange-400 transition-all duration-300 ease-out">
                    <input
                      type="text"
                      placeholder="Enter Pincode Here"
                      value={pincode}
                      onChange={(e) => setPincode(e.target.value)}
                      className="w-full sm:w-40 px-3 py-2 text-sm outline-none border-none bg-transparent"
                    />
                    <button className="bg-transparent text-[#f97316] font-bold text-xs tracking-wide px-4 py-2 border-l border-gray-300 hover:bg-orange-50 active:bg-orange-100 transition-colors duration-200 outline-none">
                      CHECK
                    </button>
                  </div>
                </div>
              </div>

              {/* Cart Items List */}
              <div className="flex flex-col">
                {items.map((item, index) => {
                  const price = getSafePrice(item);
                  const mrp = getSafeMrp(item);
                  const discountPercent = Math.round(((mrp - price) / mrp) * 100);

                  return (
                    <div key={`${item.productId}_${item.variantId}_${index}`} className="group flex flex-col sm:flex-row p-5 border-b border-gray-100 last:border-0 hover:bg-gray-50/80 transition-colors duration-300 ease-in-out">

                      {/* Product Image with Smooth Zoom */}
                      <div className="shrink-0 mb-4 sm:mb-0 overflow-hidden rounded-sm border border-gray-200 bg-gray-100">
                        <img
                          src={item.image || 'https://via.placeholder.com/150'}
                          alt={item.name}
                          className="w-full sm:w-32 h-32 object-cover transform transition-transform duration-500 ease-out group-hover:scale-[1.04]"
                        />
                      </div>

                      {/* Product Details */}
                      <div className="sm:ml-6 flex-1 flex flex-col justify-between">
                        <div>
                          <h3 className="text-base font-semibold text-gray-900 tracking-tight leading-snug group-hover:text-[#f97316] transition-colors duration-300">
                            {item.name}
                          </h3>
                          <p className="text-xs text-gray-500 mt-1 font-medium">
                            Variant: {item.variantId}
                          </p>

                          <div className="mt-3 flex flex-wrap items-center gap-x-6 gap-y-3">

                            {/* Quantity Selector using your hook */}
                            <div className="flex items-center">
                              <span className="text-sm font-medium text-gray-700 mr-3">Qty.</span>
                              <div className="flex items-center border border-gray-300 rounded-sm bg-white transition-colors duration-200 hover:border-gray-400">
                                <button
                                  onClick={() => {
                                    if (item.quantity > 1) {
                                      changeQuantity(item.productId, item.variantId, item.quantity - 1)
                                    }
                                  }}
                                  className="w-8 h-8 flex items-center justify-center text-gray-600 hover:bg-orange-50 hover:text-[#f97316] active:scale-90 transition-all duration-200 outline-none"
                                >
                                  -
                                </button>
                                <span className="w-10 h-8 flex items-center justify-center text-sm font-semibold border-x border-gray-200">
                                  {item.quantity}
                                </span>
                                <button
                                  onClick={() => changeQuantity(item.productId, item.variantId, item.quantity + 1)}
                                  className="w-8 h-8 flex items-center justify-center text-gray-600 hover:bg-orange-50 hover:text-[#f97316] active:scale-90 transition-all duration-200 outline-none"
                                >
                                  +
                                </button>
                              </div>
                            </div>

                            {/* Pricing Block */}
                            <div className="flex flex-col">
                              <span className="text-[11px] font-semibold tracking-wide text-[#22c55e] mb-0.5">
                                Limited-Time Deal
                              </span>
                              <div className="flex items-baseline gap-2">
                                <span className="text-lg font-bold text-gray-900">
                                  ₹{price.toLocaleString('en-IN')}
                                </span>
                                <span className="text-sm text-gray-400 line-through font-medium">
                                  ₹{mrp.toLocaleString('en-IN')}
                                </span>
                                <span className="text-sm font-bold text-[#22c55e]">
                                  {discountPercent}% OFF
                                </span>
                              </div>
                            </div>

                          </div>
                        </div>

                        {/* Action Buttons using your hook */}
                        <div className="flex items-center gap-6 mt-5 pt-4 border-t border-gray-100 sm:border-0 sm:pt-0 sm:mt-auto text-sm font-semibold text-gray-500">
                          <button className="flex items-center gap-1.5 hover:text-[#f97316] transition-colors duration-200 outline-none group/btn">
                            <Heart size={16} className="group-hover/btn:fill-orange-50 transition-colors duration-200" />
                            Save For Later
                          </button>
                          <button
                            onClick={() => removeItem(item.productId, item.variantId)}
                            className="flex items-center gap-1.5 hover:text-red-500 transition-colors duration-200 outline-none"
                          >
                            <Trash2 size={16} />
                            Remove
                          </button>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* ----------------------------------------------------- */}
          {/* RIGHT COLUMN: PRICE DETAILS & CHECKOUT */}
          {/* ----------------------------------------------------- */}
          <div className="lg:col-span-4 flex flex-col gap-4 sticky top-6">

            {/* Coupon Banner */}
            <div className="bg-white shadow-sm rounded-sm p-4 border border-gray-100 hover:border-gray-200 transition-colors duration-300">
              <div className="flex flex-col gap-3">
                <div className="flex items-center justify-between cursor-pointer group">
                  <div className="flex items-center gap-2">
                    <Tag size={18} className="text-[#f97316] group-hover:scale-110 transition-transform duration-300" />
                    <span className="text-sm font-medium text-gray-800">
                      <span className="font-bold text-[#f97316]">LOGIN</span> to unlock coupons!
                    </span>
                  </div>
                  <ChevronRight size={18} className="text-gray-400 group-hover:text-[#f97316] group-hover:translate-x-1 transition-all duration-300" />
                </div>

                {isCouponApplied && (
                  <div className="flex items-start justify-between bg-green-50/50 p-3 rounded-sm border border-green-100 mt-1 transition-all duration-500 ease-in-out">
                    <div className="flex flex-col">
                      <span className="text-sm text-gray-800 font-medium">
                        Coupon Applied: <span className="font-bold">{couponCode}</span>
                      </span>
                      <span className="text-xs text-[#22c55e] font-medium mt-0.5">
                        You have saved ₹{couponDiscount.toLocaleString('en-IN')}
                      </span>
                    </div>
                    <button
                      onClick={() => setIsCouponApplied(false)}
                      className="text-xs font-bold text-[#f97316] border border-[#f97316] px-3 py-1.5 rounded-sm hover:bg-orange-50 active:bg-orange-100 transition-colors duration-200 outline-none tracking-wide"
                    >
                      CHANGE
                    </button>
                  </div>
                )}
              </div>
            </div>

            {/* Price Details Card */}
            <div className="bg-white shadow-sm rounded-sm border border-gray-100 hover:border-gray-200 transition-colors duration-300 flex flex-col">

              <div className="p-4 border-b border-gray-100">
                <h3 className="text-base font-semibold text-gray-800">
                  Price Detail <span className="font-normal text-gray-500 text-sm">({totalItems} Items)</span>
                </h3>
              </div>

              <div className="p-4 space-y-4">
                <div className="flex justify-between items-center text-sm font-medium text-gray-700">
                  <span>MRP</span>
                  <span>₹{totalMrp.toLocaleString('en-IN')}</span>
                </div>
                <div className="flex justify-between items-center text-sm font-medium text-gray-700">
                  <span>Discount</span>
                  <span className="text-[#22c55e]">- ₹{baseDiscount.toLocaleString('en-IN')}</span>
                </div>
                {isCouponApplied && (
                  <div className="flex justify-between items-center text-sm font-medium text-gray-700">
                    <span>Coupon ({couponCode})</span>
                    <span className="text-[#22c55e]">- ₹{couponDiscount.toLocaleString('en-IN')}</span>
                  </div>
                )}
              </div>

              <div className="px-4 py-5 border-t border-gray-100 border-dashed bg-gray-50/50">
                <div className="flex justify-between items-start">
                  <span className="text-base font-semibold text-gray-900">Total Payable</span>
                  <div className="flex flex-col items-end">
                    <span className="text-xl font-bold text-gray-900">
                      ₹{finalPayable.toLocaleString('en-IN')}
                    </span>
                    <span className="text-[10px] text-gray-500 mt-1">Inclusive of all taxes</span>
                  </div>
                </div>
              </div>

              {totalSavings > 0 && (
                <div className="p-3.5 bg-[#f0fdf4] border-t border-[#bbf7d0]">
                  <p className="text-sm font-medium text-[#166534] text-center">
                    Congratulations! You've Just saved ₹{totalSavings.toLocaleString('en-IN')} On Your Order.
                  </p>
                </div>
              )}
            </div>

            {/* EMI & Checkout */}
            <div className="mt-2 flex flex-col gap-4">
              <p className="text-xs text-gray-500 text-center font-medium">
                EMI Starting ₹2,085/Month
              </p>
              <button
                onClick={() => navigate('/checkout')}
                className="w-full bg-[#e87831] text-white py-4 rounded-sm font-bold tracking-wide hover:bg-[#d46624] hover:shadow-lg hover:shadow-orange-500/20 active:scale-[0.98] transform transition-all duration-300 outline-none"
              >
                PLACE ORDER
              </button>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
};

export default CartPage;
